// C99 兼容的 alignof 实现
#define uya_alignof(type) offsetof(struct { char c; type t; }, t)

static inline void *__uya_memcpy(void *dest, const void *src, size_t n) {
    char *d = (char *)dest; const char *s = (const char *)src;
    for (size_t i = 0; i < n; i++) d[i] = s[i];
    return dest;
}
static inline int __uya_memcmp(const void *s1, const void *s2, size_t n) {
    const unsigned char *a = (const unsigned char *)s1, *b = (const unsigned char *)s2;
    for (size_t i = 0; i < n; i++) { if (a[i] != b[i]) return a[i] - b[i]; } return 0;
}

// syscall write - 写入文件描述符
static long uya_write(int fd, const char *buf, unsigned long len) {
    long ret;
    __asm__ volatile ("syscall" : "=a"(ret) : "a"(1), "D"(fd), "S"(buf), "d"(len) : "rcx", "r11", "memory");
    return ret;
}

// strlen - 计算字符串长度
static unsigned long uya_strlen(const char *s) {
    unsigned long len = 0;
    while (s[len]) len++;
    return len;
}

// _start - 自定义程序入口（无 C 标准库，内联汇编实现）
extern int32_t main(int32_t argc, uint8_t **argv);
__attribute__((naked)) void _start(void) {
    __asm__ volatile (
        "movq (%%rsp), %%rdi\n\t"    /* argc */
        "leaq 8(%%rsp), %%rsi\n\t"   /* argv */
        "call main\n\t"
        "movq %%rax, %%rdi\n\t"
        "movq $60, %%rax\n\t"        /* syscall exit */
        "syscall\n\t"
        "hlt\n\t"
        : : : "memory"
    );
}

