static __attribute__((unused)) size_t align_size(size_t size, size_t align) {
    (void)size;
    (void)align;
    size_t _uya_ret = ((((size + align) - 1) / align) * align);
    return _uya_ret;
}

static __attribute__((unused)) void arena_init(struct Arena * arena, uint8_t * buffer, size_t size) {
    (void)arena;
    (void)buffer;
    (void)size;
    if (((arena == NULL) || (buffer == NULL))) {
        return;
    }
    arena->buffer = buffer;
    arena->size = size;
    arena->offset = 0;
    arena->first_chunk = NULL;
    arena->current_chunk = NULL;
    arena->total_allocated = 0;
}

uint8_t * arena_alloc(struct Arena * arena, size_t size) {
    (void)arena;
    (void)size;
    if ((arena == NULL)) {
        fprintf(stderr, (const char *)str370);
        exit(1);
    }
    const size_t aligned_size = align_size(size, ARENA_ALIGNMENT);
    if ((arena->buffer != NULL)) {
        const size_t aligned_offset = align_size(arena->offset, ARENA_ALIGNMENT);
        if (((aligned_offset + aligned_size) <= arena->size)) {
            uint8_t * const result = (&arena->buffer[aligned_offset]);
            arena->offset = (aligned_offset + aligned_size);
            arena->total_allocated = (arena->total_allocated + aligned_size);
            uint8_t * _uya_ret = result;
            return _uya_ret;
        }
    }
    if ((arena->current_chunk != NULL)) {
        struct ArenaChunk * const chunk = arena->current_chunk;
        const size_t chunk_offset = align_size(chunk->used, ARENA_ALIGNMENT);
        if (((chunk_offset + aligned_size) <= chunk->size)) {
            uint8_t * const result = (&chunk->buffer[chunk_offset]);
            chunk->used = (chunk_offset + aligned_size);
            arena->total_allocated = (arena->total_allocated + aligned_size);
            uint8_t * _uya_ret = result;
            return _uya_ret;
        }
    }
    size_t chunk_size = ARENA_CHUNK_SIZE;
    if ((aligned_size > ARENA_CHUNK_SIZE)) {
        chunk_size = aligned_size;
    }
    uint8_t * const chunk_mem = (uint8_t *)malloc((int32_t)sizeof(struct ArenaChunk));
    if ((chunk_mem == NULL)) {
        fprintf(stderr, (const char *)str371);
        exit(1);
    }
    struct ArenaChunk * const new_chunk = (struct ArenaChunk *)chunk_mem;
    uint8_t * const buffer_mem = (uint8_t *)malloc(chunk_size);
    if ((buffer_mem == NULL)) {
        fprintf(stderr, (const char *)str372, chunk_size);
        exit(1);
    }
    new_chunk->buffer = buffer_mem;
    new_chunk->size = chunk_size;
    new_chunk->used = 0;
    new_chunk->next = NULL;
    if ((arena->first_chunk == NULL)) {
        arena->first_chunk = new_chunk;
    } else {
        struct ArenaChunk * last = arena->first_chunk;
        while ((last->next != NULL)) {
            last = last->next;
        }
        last->next = new_chunk;
    }
    arena->current_chunk = new_chunk;
    const size_t result_offset = align_size(new_chunk->used, ARENA_ALIGNMENT);
    uint8_t * const result = (&new_chunk->buffer[result_offset]);
    new_chunk->used = (result_offset + aligned_size);
    arena->total_allocated = (arena->total_allocated + aligned_size);
    uint8_t * _uya_ret = result;
    return _uya_ret;
}

static __attribute__((unused)) size_t arena_save(struct Arena * arena) {
    (void)arena;
    if ((arena == NULL)) {
        size_t _uya_ret = 0;
        return _uya_ret;
    }
    size_t _uya_ret = arena->offset;
    return _uya_ret;
}

static __attribute__((unused)) void arena_restore(struct Arena * arena, size_t offset) {
    (void)arena;
    (void)offset;
    if ((arena == NULL)) {
        return;
    }
    if ((offset <= arena->size)) {
        arena->offset = offset;
    }
}

